input.command:
ADMIN=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
echo "admin pw: $ADMIN"
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet -u admin -p "$ADMIN" --authenticationDatabase admin --eval "
rs.status().ok;
print('---users---');
db.getSiblingDB('admin').system.users.find({}, {user:1,db:1,roles:1}).forEach(printjson);
" 2>&1 | head -60

# Check if auth even works without credentials (localhost exception) and replica state
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval "
try { print('rs:', JSON.stringify(rs.status().members.map(m=>({n:m.name,s:m.stateStr})))); } catch(e){ print('rserr:', e.message); }
print('---');
try { db.getSiblingDB('admin').system.users.find({},{user:1,db:1}).forEach(printjson); } catch(e){ print('usererr:', e.message); }
" 2>&1 | head -40

kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval "
printjson(db.runCommand({connectionStatus:1}));
print('--- try create via localhost exception ---');
try{ printjson(db.getSiblingDB('admin').runCommand({usersInfo:1})) }catch(e){print('usersInfo:',e.codeName)}
" 2>&1 | head -30

