A=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}'|base64 -d)
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet -u admin-user -p "$A" --authenticationDatabase admin --eval "
var adb = db.getSiblingDB('admin');
// 1) app-user: grant readWrite on appdb (and remove plain read to keep clean)
adb.runCommand({grantRolesToUser:'app-user', roles:[{role:'readWrite', db:'appdb'}]});
adb.runCommand({revokeRolesFromUser:'app-user', roles:[{role:'read', db:'appdb'}]});

// 2) create custom role reportingRole in appdb: read access to appdb.reports
var appdb = db.getSiblingDB('appdb');
var existing = appdb.getRole('reportingRole');
if(!existing){
  appdb.runCommand({createRole:'reportingRole',
    privileges:[{resource:{db:'appdb',collection:'reports'}, actions:['find','listIndexes','listCollections']}],
    roles:[]});
  print('created reportingRole');
}

// 3) readonly-user: ensure read on appdb + reportingRole
adb.runCommand({grantRolesToUser:'readonly-user', roles:[{role:'read', db:'appdb'},{role:'reportingRole', db:'appdb'}]});

print('=== final ===');
printjson(adb.getUser('app-user').roles);
printjson(adb.getUser('readonly-user').roles);
" 2>&1 | tail -30

